Here's an example of a Go program that uses GPT-3 to generate alternative phrasings:

```go
package main

import (
	"context"
	"fmt"
	"log"
	"strings"

	gpt3 "github.com/1ambda/go-gpt-3/pkg/client"
)

func rephraseSentence(input, apiKey string) string {
	client, err := gpt3.NewClient(apiKey) // Replace "apiKey" with your API key.
	if err != nil {
		log.Fatalln("Failed to set up GPT-3 client:", err)
	}

	// Construct prompt for GPT-3
	prompt := fmt.Sprintf("Rewrite the following sentence with alternative phrasing while maintaining proper grammar and spelling: \"%s\"", input)

	// Define the config for GPT-3.
	conf := gpt3.CompletionConfig{
		Engine:   "davinci-codex",
		Prompt:   prompt,
		MaxTokens: 40,
		N:        1,
		Stop:     []string{"\""},
	}

	ctx := context.Background()
	resp, err := client.Completion(ctx, conf)
	if err != nil {
		log.Fatalln("Failed to get completion from GPT-3:", err)
	}

	if len(resp.Choices) > 0 {
		return strings.TrimSpace(resp.Choices[0].Text)
	}
	return ""
}

func main() {
	input := "While indulging in my hobby of bird watching, I frequently observe an array of avian species in their natural habitat."
	apiKey := "PUT_YOUR_API_KEY_HERE"

	rephrased := rephraseSentence(input, apiKey)
	fmt.Println("Original sentence:", input)
	fmt.Println("Rephrased sentence:", rephrased)
}
```

Replace `PUT_YOUR_API_KEY_HERE` with your OpenAI API key. The program sends the input sentence to GPT-3 and retrieves rewritten phrasings of the input sentence. Please note that GPT-3 has usage limits, and you may incur costs when using this or similar APIs.

