# Callback function for processing ImageStreams from camera
def image_callback(msg):
    try:
        cv_image = CvBridge().imgmsg_to_cv2(msg, "bgr8")
        barcodes = decode(cv_image)

        for decodedObject in barcodes:
            barcode_data = decodedObject.data.decode('utf-8')

            category, quantity = process_barcode_data(barcode_data)
            if category in inventory.categories:
                inventory.update_inventory(category, quantity)
                rospy.loginfo(f"Updated inventory for {category}.")
                # Add robotic arm control and conveyor belt control code here.

    except CvBridgeError as e:
        print(e)
        return

# Subscriber for ImageStreams from camera
image_sub = rospy.Subscriber('/camera/image_raw', Image, image_callback)

try:
    rospy.spin()
except KeyboardInterrupt:
    print("Shutting down")
